import React from 'react';

interface SkeletonProps {
  width?: string;
  height?: string;
  variant?: 'text' | 'rect' | 'circle';
  lines?: number;
  className?: string;
}

const Skeleton: React.FC<SkeletonProps> = ({
  width,
  height,
  variant = 'text',
  lines = 1,
  className = '',
}) => {
  const baseClasses = `animate-pulse border-2 border-zap-border ${className}`;
  const bgClasses = 'bg-zap-bg-alt/90 dark:bg-zap-border/35';

  if (variant === 'text') {
    return (
      <div className="flex flex-col gap-2">
        {Array.from({ length: lines }).map((_, i) => (
          <div
            key={i}
            className={`${baseClasses} ${bgClasses} rounded-full`}
            style={{
              width: width || (lines > 1 && i === lines - 1 ? '70%' : '100%'),
              height: height || '1rem',
            }}
          />
        ))}
      </div>
    );
  }

  return (
    <div
      data-testid={`skeleton-${variant}`}
      className={`${baseClasses} ${bgClasses} ${variant === 'circle' ? 'rounded-full' : 'rounded-none'
        }`}
      style={{
        width: width || (variant === 'circle' ? '3rem' : '100%'),
        height: height || (variant === 'circle' ? '3rem' : '10rem'),
      }}
    />
  );
};

export default Skeleton;
